// Calcula chaves de cache e normaliza entrada
const crypto = require('crypto');
const t = $input.first().json;
const query = (t.query || '').toString();
const qNorm = query.toLowerCase().trim();
const f = t.filters || {};
const topic = f.topic || null;
const subtopic = f.subtopic || null;
const categoria = f.categoria ?? f.categoria_cabine ?? null;
const navio = (f.navio ?? t.navio ?? null) || null;
const top_k = Number(t.top_k) || 3;

if (!qNorm) throw new Error('query vazia');

const fingerprint = `${qNorm}|t=${topic||''}|s=${subtopic||''}|c=${categoria||''}|n=${navio||''}|k=${top_k}`;
const resultHash = crypto.createHash('md5').update(fingerprint).digest('hex');

return [{
  json: {
    query,
    topic,
    subtopic,
    categoria,
    navio,
    top_k,
    cacheKeyResult: `kb:result:${topic||'_'}:${navio||'_'}:${resultHash}`,
    __t0: Date.now()
  }
}];

// Cache HIT — devolve direto com flag fromCache
const v = $json.cachedResult;
const parsed = typeof v === 'string' ? JSON.parse(v) : v;
return [{ json: { ...parsed, fromCache: true } }];

// Gera literais SQL-escapados para inlinar na query.
// Evita o bug do queryReplacement que faz split por vírgula (quebra o vector).
const raw = $input.first().json;
const emb = Array.isArray(raw[0]) ? raw[0] : (Array.isArray(raw.data) ? raw.data[0] : raw);
if (!Array.isArray(emb) || typeof emb[0] !== 'number') {
  throw new Error('Embedding em formato inesperado: ' + JSON.stringify(raw).slice(0, 200));
}
const p = $('Preparar Chaves1').first().json;

const sqlStr = v => (v === null || v === undefined || v === '')
  ? 'NULL'
  : `'${String(v).replace(/'/g, "''")}'`;

return [{
  json: {
    emb_vector_literal: `'[${emb.join(',')}]'::vector`,
    query_sql: sqlStr(p.query),
    topic_sql: sqlStr(p.topic),
    subtopic_sql: sqlStr(p.subtopic),
    categoria_sql: sqlStr(p.categoria),
    navio_sql: sqlStr(p.navio),
    query: p.query,
    topic: p.topic,
    subtopic: p.subtopic,
    categoria: p.categoria,
    navio: p.navio,
    top_k: p.top_k,
    cacheKeyResult: p.cacheKeyResult,
    __t0: p.__t0
  }
}];

