// Sem candidatos — retorna vazio sem chamar rerank
const p = $('Preparar Params1').first().json;
return [{
  json: {
    results: [],
    contexto: '',
    sources: [],
    tem_resultado: false,
    fromCache: false,
    cacheKeyResult: p.cacheKeyResult,
    _telemetria: {
      query: p.query,
      topic: p.topic,
      top_chunk_id: null,
      top_score: 0,
      has_result: false,
      latency_ms: Date.now() - (p.__t0 || Date.now())
    }
  }
}];

// HTTP Request v4.2 splita arrays em múltiplos items; usar $input.all() para remontar.
const rerankRaw = $input.all().map(i => i.json);
const rerank = (rerankRaw.length === 1 && Array.isArray(rerankRaw[0])) ? rerankRaw[0] : rerankRaw;
const rows = $('Busca Hibrida1').all().map(i => i.json);
const params = $('Preparar Params1').first().json;
const top_k = params.top_k;
const MIN_SCORE = 0.05;   // bge-reranker-base (CPU) roda em escala menor que v2-m3 — 0.25 era threshold do v2-m3

// Short-circuit: se a busca híbrida retornou apenas 1 candidato, o rerank não pode
// reordenar nada e o MIN_SCORE pode descartar o único match legítimo. Usa o score
// bruto da busca híbrida (já validado pelo SQL kb_hybrid_search) sem filtrar.
const singleRow = rows.length === 1;

const ranked = singleRow
  ? rows.slice(0, top_k).map(r => ({ ...r, score: typeof r.score === 'number' ? r.score : 1.0 }))
  : rerank
      .map(r => ({ ...rows[r.index], score: r.score }))
      .filter(r => r.score >= MIN_SCORE)
      .sort((a, b) => b.score - a.score)
      .slice(0, top_k);

const contexto = ranked.length
  ? ranked.map((r, i) => `[#${i+1} · ${r.title} · ${r.topic}${r.subtopic ? '/' + r.subtopic : ''}]\n${r.content}`).join('\n\n---\n\n')
  : '';

const sources = [...new Set(ranked.map(r => r.fonte).filter(Boolean))];

return [{
  json: {
    results: ranked.map(r => ({
      doc_id: r.chunk_id,
      topic: r.topic,
      subtopic: r.subtopic,
      title: r.title,
      content: r.content,
      keywords: r.keywords,
      aliases: r.aliases,
      score: r.score,
      fonte: r.fonte,
      categoria_cabine: r.categoria_cabine
    })),
    contexto,
    sources,
    tem_resultado: ranked.length > 0,
    fromCache: false,
    cacheKeyResult: params.cacheKeyResult,
    _telemetria: {
      query: params.query,
      topic: params.topic,
      top_chunk_id: ranked[0]?.chunk_id || null,
      top_score: ranked[0]?.score || 0,
      has_result: ranked.length > 0,
      latency_ms: Date.now() - (params.__t0 || Date.now()),
      rerank_skipped: singleRow
    }
  }
}];

// Saída final limpa — remove campos internos
const d = $input.first().json;
return [{
  json: {
    results: d.results,
    contexto: d.contexto,
    sources: d.sources,
    tem_resultado: d.tem_resultado,
    fromCache: d.fromCache || false
  }
}];

// Cache HIT — devolve direto com flag fromCache
const v = $json.cachedResult;
const parsed = typeof v === 'string' ? JSON.parse(v) : v;
return [{ json: { ...parsed, fromCache: true } }];

// Envia ao rerank: title + aliases + keywords + content — ajuda o cross-encoder
// a casar gírias/sinônimos que estão em aliases mas NÃO no corpo do texto.
const rows = $input.all().map(i => i.json);
return [{
  json: {
    bodyJson: {
      query: $('Preparar Chaves1').first().json.query,
      texts: rows.map(r => {
        const titleLine = r.title ? `${r.title}\n` : '';
        const aliasLine = (r.aliases && r.aliases.length) ? `Também chamado de: ${r.aliases.join(', ')}.\n` : '';
        const kwLine    = (r.keywords && r.keywords.length) ? `Palavras-chave: ${r.keywords.join(', ')}.\n` : '';
        return `${titleLine}${aliasLine}${kwLine}\n${r.content}`;
      }),
      raw_scores: false,
      truncate: true,
      truncation_direction: "Right"
    },
    rows
  }
}];
